const data = $input.first().json;
const state = data.conversation_state;
const messageText = (data.messageText || '').trim();

let action = 'unknown';

switch(state) {
  case 'SCHEDULING_SPECIALTY':
    action = 'LIST_SPECIALTIES';
    break;
  case 'SCHEDULING_DOCTOR':
    action = 'SELECT_DOCTOR';
    break;
  case 'SCHEDULING_SLOT':
    action = 'SELECT_SLOT';
    break;
  case 'SCHEDULING_CONFIRM':
    action = 'CONFIRM_APPOINTMENT';
    break;
  default:
    action = 'LIST_SPECIALTIES';
}

return [{ json: { ...data, action, userChoice: messageText } }];

const data = $('Determinar etapa').first().json;
const specialties = $input.all().map(item => item.json.specialty);

let text = '🏥 *Especialidades disponíveis:*\n\n';
specialties.forEach((s, i) => {
  text += `${i + 1}️⃣ ${s}\n`;
});
text += '\nDigite o *número* da especialidade desejada.';

return [{
  json: {
    ...data,
    responseText: text,
    specialtiesList: specialties,
    newState: 'SCHEDULING_DOCTOR'
  }
}];

// Recupera especialidades da conversa e identifica a escolha
const data = $('Determinar etapa').first().json;
const userChoice = (data.userChoice || '').trim();

// Usuário quer cancelar o agendamento
if (userChoice === '0') {
  return [{ json: { ...data, selectedSpecialty: null, validChoice: false, cancelled: true, rePromptText: '' } }];
}

const choice = parseInt(userChoice);

let specialties = [];
try {
  const msgs = typeof data.messages === 'string' ? JSON.parse(data.messages) : (data.messages || []);
  for (const m of msgs) {
    if (m.specialties) {
      specialties = typeof m.specialties === 'string' ? JSON.parse(m.specialties) : m.specialties;
    }
  }
} catch(e) {}

const selectedSpecialty = specialties[choice - 1] || null;

let rePromptText = '';
if (!selectedSpecialty) {
  rePromptText = '⚠️ Não entendi. Por favor, envie apenas o *número* da especialidade:\n\n';
  specialties.forEach((s, i) => { rePromptText += `${i+1}️⃣ ${s}
`; });
  rePromptText += '\nDigite o *número* desejado.';
}

return [{
  json: {
    ...data,
    selectedSpecialty,
    validChoice: selectedSpecialty !== null,
    cancelled: false,
    rePromptText
  }
}];

const data = $('Identificar especialidade escolhida').first().json;
const doctors = $input.all().map(item => ({
  id: item.json.id,
  name: item.json.name
}));

let text = `👨‍⚕️ *Médicos de ${data.selectedSpecialty}:*\n\n`;
doctors.forEach((d, i) => {
  text += `${i + 1}️⃣ ${d.name}\n`;
});
text += '\nDigite o *número* do médico desejado.';

return [{
  json: {
    ...data,
    responseText: text,
    doctorsList: doctors,
    newState: 'SCHEDULING_SLOT'
  }
}];

// Identifica médico escolhido e busca horários no banco de dados local
const data = $('Determinar etapa').first().json;
const userChoice = (data.userChoice || '').trim();

// Usuário quer cancelar o agendamento
if (userChoice === '0') {
  return [{ json: { ...data, error: true, cancelled: true, rePromptText: '' } }];
}

const choice = parseInt(userChoice);

let doctors = [];
try {
  const msgs = typeof data.messages === 'string' ? JSON.parse(data.messages) : (data.messages || []);
  for (const m of msgs) {
    if (m.doctors) {
      doctors = typeof m.doctors === 'string' ? JSON.parse(m.doctors) : m.doctors;
    }
  }
} catch(e) {}

const selectedDoctor = doctors[choice - 1] || null;

if (!selectedDoctor) {
  let rePromptText = '⚠️ Não entendi. Por favor, envie apenas o *número* do médico:\n\n';
  doctors.forEach((d, i) => { rePromptText += `${i+1}️⃣ ${d.name}\n`; });
  rePromptText += '\nDigite o *número* desejado.';
  return [{ json: { ...data, error: true, cancelled: false, rePromptText } }];
}

// Preparar busca de horários no banco
const now = new Date();
const oneWeekLater = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);

return [{
  json: {
    ...data,
    error: false,
    cancelled: false,
    selectedDoctor,
    doctor_id: selectedDoctor.id,
    doctor_name: selectedDoctor.name,
    freeBusyTimeMin: now.toISOString(),
    freeBusyTimeMax: oneWeekLater.toISOString()
  }
}];

const prevData = $('Identificar médico e buscar horários').first().json;
const dbAppointments = $input.all().map(item => item.json.scheduled_at).filter(Boolean);

const businessStart = 8;
const businessEnd = 18;
const slotDurationMin = 30;
const MAX_SLOTS = 200;

const busyPeriods = dbAppointments.map(d => ({
  start: new Date(d).getTime(),
  end: new Date(d).getTime() + slotDurationMin * 60 * 1000
}));

const allSlots = [];
const now = new Date();

for (let day = 0; day < 14 && allSlots.length < MAX_SLOTS; day++) {
  const date = new Date(now);
  date.setDate(date.getDate() + day);
  if (date.getDay() === 0 || date.getDay() === 6) continue;

  for (let hour = businessStart; hour < businessEnd && allSlots.length < MAX_SLOTS; hour++) {
    for (let min = 0; min < 60 && allSlots.length < MAX_SLOTS; min += slotDurationMin) {
      const slotStart = new Date(date);
      slotStart.setHours(hour, min, 0, 0);
      if (slotStart.getTime() <= now.getTime()) continue;

      const slotEnd = new Date(slotStart.getTime() + slotDurationMin * 60 * 1000);
      const isBusy = busyPeriods.some(bp =>
        slotStart.getTime() < bp.end && slotEnd.getTime() > bp.start
      );

      if (!isBusy) {
        allSlots.push({
          start: slotStart.toISOString(),
          end: slotEnd.toISOString(),
          display: slotStart.toLocaleDateString('pt-BR', { weekday: 'short', day: '2-digit', month: '2-digit' }) + 
                   ' às ' + slotStart.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })
        });
      }
    }
  }
}

const pageSlots = allSlots.slice(0, 5);
const hasMore = allSlots.length > 5;
const hasNextDay = allSlots.findIndex(s => s.display.split(' às ')[0] !== pageSlots[0]?.display.split(' às ')[0]) !== -1;

let text = `📅 *Horários disponíveis com ${prevData.doctor_name}:*

`;
pageSlots.forEach((s, i) => { text += `${i + 1}️⃣ ${s.display}
`; });
if (hasMore) text += `
➡️ *6* = Ver mais horários`;
if (hasNextDay) text += `
⏭️ *7* = Próximo dia`;
text += `
0️⃣ Cancelar

Digite o *número* do horário desejado.`;

if (allSlots.length === 0) {
  text = `Infelizmente não há horários disponíveis para ${prevData.doctor_name} nos próximos 14 dias. 😔\n\nEnvie qualquer mensagem para voltar ao menu.`;
}

return [{
  json: {
    ...prevData,
    availableSlots: pageSlots,
    allSlots,
    responseText: text,
    hasSlots: allSlots.length > 0
  }
}];

const data = $('Determinar etapa').first().json;
const choice = (data.userChoice || '').trim().toLowerCase();

let allSlots = [];
let currentOffset = 0;
let doctorId = '';
let doctorName = '';
try {
  const msgs = typeof data.messages === 'string' ? JSON.parse(data.messages) : (data.messages || []);
  for (const m of msgs) {
    if (m.allSlots) allSlots = typeof m.allSlots === 'string' ? JSON.parse(m.allSlots) : m.allSlots;
    if (m.slotOffset !== undefined) currentOffset = parseInt(m.slotOffset); else if (m.slotsPage !== undefined) currentOffset = parseInt(m.slotsPage) * 5;
    if (m.doctor_id) doctorId = m.doctor_id;
    if (m.doctor_name) doctorName = m.doctor_name;
  }
} catch(e) {}

const pageSlots = allSlots.slice(currentOffset, currentOffset + 5);
const choiceNum = parseInt(choice);
const isCancelIntent = choice === '0' || ['cancelar', 'sair', 'voltar'].includes(choice);
const hasMoreSlots = allSlots.length > currentOffset + 5;
const isNextPage = choiceNum === 6 && hasMoreSlots;

const currentDayStr = pageSlots.length > 0 ? pageSlots[0].display.split(' às ')[0] : '';
let nextDayIndex = -1;
for (let i = currentOffset + 5; i < allSlots.length; i++) {
  if (allSlots[i].display.split(' às ')[0] !== currentDayStr) {
    nextDayIndex = i;
    break;
  }
}
const hasNextDayChoice = nextDayIndex !== -1;
const isNextDay = choiceNum === 7 && hasNextDayChoice;

if (isNextPage || isNextDay) {
  let nextOffset = currentOffset + 5;
  if (isNextDay) {
    nextOffset = nextDayIndex;
  }

  const nextSlots = allSlots.slice(nextOffset, nextOffset + 5);
  const hasMoreAfter = allSlots.length > nextOffset + 5;
  const nextDayStr = nextSlots.length > 0 ? nextSlots[0].display.split(' às ')[0] : '';
  const hasNextDayAfter = allSlots.findIndex((s, i) => i >= nextOffset + 5 && s.display.split(' às ')[0] !== nextDayStr) !== -1;

  let moreText = `📅 *Mais horários com ${doctorName}:*

`;
  nextSlots.forEach((s, i) => { moreText += `${i+1}️⃣ ${s.display}
`; });
  if (hasMoreAfter) moreText += `
➡️ *6* = Ver mais horários`;
  if (hasNextDayAfter) moreText += `
⏭️ *7* = Próximo dia`;
  moreText += `
0️⃣ Cancelar

Digite o *número* do horário desejado.`;

  return [{ json: { ...data, wantsMore: true, slotOffset: nextOffset, nextSlotsText: moreText, allSlots, doctor_id: doctorId, doctor_name: doctorName, confirmed: false, cancelled: false, invalidInput: false } }];
}const selectedSlot = pageSlots[choiceNum - 1] || null;

if (!selectedSlot) {
  let rePromptText = '';
  if (!isCancelIntent) {
    rePromptText = '⚠️ Não entendi. Por favor, envie apenas o *número* do horário:\n\n';
    pageSlots.forEach((s, i) => { rePromptText += `${i+1}️⃣ ${s.display}\n`; });
    if (hasMoreSlots) rePromptText += `\n➡️ *6* = Ver mais horários`;
    if (hasNextDayChoice) rePromptText += `\n⏭️ *7* = Próximo dia`;
    rePromptText += `\n\nDigite o *número* desejado, ou *0* para cancelar.`;
  }
  return [{ json: { ...data, confirmed: false, cancelled: isCancelIntent, invalidInput: !isCancelIntent, wantsMore: false, rePromptText } }];
}

return [{ json: { ...data, confirmed: true, cancelled: false, wantsMore: false, selectedSlot, doctor_id: doctorId, doctor_name: doctorName } }];
